#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long total = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                int roomNumber = i + j;
                int evenSum = 0, oddSum = 0;
                while (roomNumber > 0) {
                    int digit = roomNumber % 10;
                    if (digit % 2 == 0) evenSum += digit;
                    else oddSum += digit;
                    roomNumber /= 10;
                }
                total += abs(evenSum - oddSum);
            }
        }
        printf("%lld\n", total);
    }
    return 0;
}

