import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long total = 0;
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= N; j++) {
                    int roomNumber = i + j;
                    int evenSum = 0, oddSum = 0;
                    while (roomNumber > 0) {
                        int digit = roomNumber % 10;
                        if (digit % 2 == 0) evenSum += digit;
                        else oddSum += digit;
                        roomNumber /= 10;
                    }
                    total += Math.abs(evenSum - oddSum);
                }
            }
            System.out.println(total);
        }
    }
}

